const r=$input.first().json;const rec=(r.records||[])[0];
if(!rec) return [{json:{found:false,ok:false,reason:"Card not recognized",accountId:""}}];
const f=rec.fields;
return [{json:{found:true,accountRecordId:rec.id,accountId:f["AccountID"]||"",balance:Number(f["Balance"]||0),
 status:f["Status"]||"Active",rfid:f["RFID UID"]||"",ownerName:f["Owner Name"]||"",ownerType:f["Owner Type"]||"",ownerId:f["Owner ID"]||""}}];

const acc=$('Parse account').first().json;
if(!acc.found) return [{json:{ok:false,reason:acc.reason||"Card not recognized"}}];
const r=$input.first().json;const srec=(r.records||[])[0];const sf=srec?srec.fields:{};
const name=sf["StudentName"]||acc.ownerName||"(unassigned card)";
return [{json:{ok:true,student:{accountId:acc.accountId,accountRecordId:acc.accountRecordId,rfid:acc.rfid,
 balance:acc.balance,status:acc.status,id:sf["StudentID"]||acc.ownerId||"",name:name,
 grade:sf["Grade Level"]||"",section:sf["Section"]||"",ownerType:acc.ownerType||(sf["StudentName"]?"Student":"")}}}];

const r=$input.first().json;const body=$('Webhook').first().json.body;const rec=(r.records||[])[0];
if(!rec) return [{json:{ok:false,proceed:false,reason:"Card not recognized"}}];
const f=rec.fields;const bal=Number(f["Balance"]||0);const total=Number(body.total||0);const status=f["Status"]||"Active";
if(status!=="Active") return [{json:{ok:false,proceed:false,reason:"Card is "+status}}];
if(bal<total) return [{json:{ok:false,proceed:false,reason:"Insufficient balance"}}];
const d=new Date(Date.now()+8*3600*1000);const z=n=>String(n).padStart(2,'0');
const receiptNo="OR-"+String(d.getUTCFullYear()).slice(2)+z(d.getUTCMonth()+1)+z(d.getUTCDate())+"-"+z(d.getUTCHours())+z(d.getUTCMinutes())+z(d.getUTCSeconds());
return [{json:{ok:true,proceed:true,accountRecordId:rec.id,accountId:f["AccountID"]||"",balanceAfter:bal-total,
 total:total,items:JSON.stringify(body.items||[]),student:body.studentName||"",receiptNo}}];

