const receiptNo="LD-"+String(d.getUTCFullYear()).slice(2)+z(d.getUTCMonth()+1)+z(d.getUTCDate())+"-"+z(d.getUTCHours())+z(d.getUTCMinutes())+z(d.getUTCSeconds());
return [{json:{ok:true,proceed:true,accountRecordId:rec.id,accountId:f["AccountID"]||"",amount:amount,
 balanceAfter:Number(f["Balance"]||0)+amount,student:body.studentName||"",receiptNo}}];

