return [{json:{ok:true,proceed:true,accountRecordId:rec.id}}];

const r=$input.first().json;const rec=(r.records||[])[0];
if(!rec) return [{json:{ok:false,reason:"Card not recognized"}}];
const f=rec.fields;
return [{json:{ok:true,template:f["Fingerprint Template"]||"",enrolled:!!f["Bio Enrolled"]}}];

const r=$input.first().json;const rec=(r.records||[])[0];
if(!rec) return [{json:{ok:false,reason:"Card not recognized"}}];
const f=rec.fields;
return [{json:{ok:true,account:{recordId:rec.id,accountId:f["AccountID"]||"",rfid:f["RFID UID"]||"",
 balance:Number(f["Balance"]||0),status:f["Status"]||"Active",ownerName:f["Owner Name"]||"",
 ownerType:f["Owner Type"]||"",ownerId:f["Owner ID"]||"",bioEnrolled:!!f["Bio Enrolled"]}}}];

const r=$input.first().json;const body=$('Webhook').first().json.body;const rec=(r.records||[])[0];
if(!rec) return [{json:{ok:false,proceed:false,reason:"Card not recognized"}}];
const f=rec.fields;const oldOwner=f["Owner Name"]||"(unassigned)";const oldBalance=Number(f["Balance"]||0);
const patch={"Owner Name":body.ownerName||"","Owner Type":body.ownerType||"Staff","Owner ID":body.ownerId||"",
 "Status":"Active","Fingerprint Template":"","Bio Enrolled":false};
if(body.clearBalance){patch["Balance"]=0;}
let reason=body.reason||"Ownership change";
if(body.clearBalance&&oldBalance>0){reason+=" (prior balance PHP "+oldBalance+" cleared for refund)";}
return [{json:{ok:true,proceed:true,accountRecordId:rec.id,accountId:f["AccountID"]||"",rfid:f["RFID UID"]||"",
 oldOwner,oldBalance,newOwner:patch["Owner Name"],newType:patch["Owner Type"],reason,patch}}];

const r=$input.first().json;const body=$('Webhook').first().json.body;const rec=(r.records||[])[0];
if(rec){const f=rec.fields;return [{json:{ok:false,proceed:false,reason:"Card already registered"+(f["Owner Name"]?(" to "+f["Owner Name"]):"")}}];}
const accountId="ACC-"+Date.now().toString(36).toUpperCase();
const fields={"AccountID":accountId,"RFID UID":body.rfid,"Owner Name":body.ownerName||"","Owner Type":body.ownerType||"Student","Owner ID":body.ownerId||"","Balance":0,"Status":"Active"};
return [{json:{ok:true,proceed:true,accountId,owner:fields["Owner Name"],fields}}];

const r=$input.first().json;const body=$('Webhook').first().json.body;const rec=(r.records||[])[0];
if(!rec) return [{json:{ok:false,proceed:false,reason:"Card not recognized"}}];
const f=rec.fields;
const fields={
 "Entry":"AT-"+Date.now().toString(36).toUpperCase(),
 "AccountID":f["AccountID"]||"",
 "RFID UID":f["RFID UID"]||"",
 "Student":f["Owner Name"]||"",
 "Direction":body.direction||"In",
 "Method":body.method||"Face",
 "Device":body.device||"Dahua ASI3213A-W",
 "Timestamp":new Date().toISOString()
};
return [{json:{ok:true,proceed:true,student:fields["Student"],direction:fields["Direction"],fields}}];
